        new (&self->redoc_url) std::string("/redoc");
        new (&self->oauth2_redirect_url) std::string("/docs/oauth2-redirect");
        // Rate limiting + logging hook
        self->rate_limit_enabled = false;
        self->rate_limit_max_requests = 100;
